INSERT INTO public.dm_templates (name, content, outreach_type, description)
VALUES (
  'FOTM Welcome — Personal',
  E'Hey {{first_name}},\n\nHenry here. I saw you just joined From Oven to Market, and I wanted to say welcome personally, not with some auto-reply, but from me to you.\n\nReal quick, so you know you landed in the right room. This is where bakers who are selling, or getting ready to, figure it out together. Pricing, cottage food law, labels, market days, the whole business side that nobody warns you about when you''re just baking for the joy of it. You''ll fit right in whether you''re prepping for your first table or you''ve been at it a while and want to get sharper.\n\nWhen you get a minute, do three things:\n\nWatch the welcome video first. It''s short and it shows you how everything''s laid out.\n\nThen head into the Classroom. The first thing you''ll see is a full walkthrough of the course, so you know what''s here and how it fits together. While you''re in there, two tools are yours free: the Loaf Calculator, so you finally know what a loaf actually costs you, and this month''s Market Kit, my exact farmers market setup. If you want a look at Recipe Pantry Pro, the production workspace built for market bakers, here''s the preview: https://skoo.ly/recipepantrypro-lite\n\nLast thing, and it''s the one that matters most. Come say hello. Drop a quick post and tell us your name, where you bake from, and what you''re working toward. The folks here are generous, and they answer.\n\nThat''s it. Look around, get comfortable, and ask me anything. Perfection isn''t the goal here. Progress is.\n\nGlad you''re with us,\n\nHenry',
  'welcome_message',
  'Default welcome DM for From Oven to Market members. Uses {{first_name}} merge tag.'
)
ON CONFLICT DO NOTHING;